UPDATE public.questions SET
  stimulus_text = 'Historians examining trade route 2 note that camel caravans carried not only goods but also astronomical tables, spreading navigation techniques across deserts long before printed maps existed. Merchants who survived the crossing depended on star charts copied onto leather scrolls, and those copies often accumulated marginal notes from later travelers. A ledger recovered near route 2 lists dates, caravan leaders, and the scientific texts exchanged at each oasis, suggesting that commerce and scholarship moved together. When one city tightened tariffs, caravans rerouted through secondary wells, and the astronomical knowledge rerouted with them. Modern scholars therefore treat desert trade networks as early information highways rather than simple supply chains. The passage emphasizes how practical navigation needs drove the circulation of technical knowledge among communities that rarely shared a written language. The team''s initial conclusion was tenuous until additional trials clarified the pattern across all three study sites.',
  question_text = 'As used in the passage, "tenuous" most nearly means',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"obvious to any casual reader of the data","is_correct":false,"explanation":"\"obvious to any casual reader of the data\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"B","text":"fragile or weakly supported","is_correct":true,"explanation":"In context, the conclusion needed revision after more trials; \"tenuous\" therefore aligns with \"or weakly supported\" in meaning. The surrounding sentence signals uncertainty resolved by additional data."},{"id":"C","text":"permanent and impossible to revise","is_correct":false,"explanation":"\"permanent and impossible to revise\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"D","text":"loud enough to dominate the entire discussion","is_correct":false,"explanation":"\"loud enough to dominate the entire discussion\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'Context shows the team''s first conclusion required revision after further trials. In that frame, "tenuous" must fit an meaning of provisional or adjustable judgment rather than certainty. Choice B matches that nuance, while the others describe opposite or irrelevant senses.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_template_v1","explanation_v2":true,"english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.880Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
